    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);

    // 2. Create a reactive variable count to track recomputation count, initialized to 0
    auto count = reaction::var(0);

    // 3. Create a calculation that sums a and b and increments count on change
    auto sum_calc = reaction::calc([&]() {
