    const bool templateAllowed = StackMonitor::canAllocate<32>();
    const bool runtimeAllowed = StackMonitor::canAllocate(64);

    StackMonitor::StackGuard<SBOConfig::MAX_SBO_STACK_USAGE - 128> guard;
